import json
from urllib import parse
# Import boto3 client from the AWS SDK (Boto 3) to interact with S3 and other services in our microservices architecture
import boto3
def lambda_handler(event, context):   # Define a handler function for Lambda events. This is where your code will run when an event occurs such as changes on the DynamoDB table or updates via API Gateway 
    sns = boto3.client('sns')     # Initialize SNS client to send notifications about errors and other information through Amazon Simple Notification Service (SNS)  
                                          
    try:                            # Try block for untrusted input validation, error handling etc...        
        body=json.loads(event['body'])  # Load the JSON data from API Gateway event into Python dictionary 'body'      
    
        if not all([key in body for key in ['bucket', 'fileName']]):   # Check that we have a bucket and file name to upload/download. If any missing, return an error message 
            sns.publish(    # Publishing the notification about failed validation of input data through SNS topic    
                TopicArn='<Your-SNS_TopicARN>',   # Replace with your actual Amazon Resource Name (ARN) for Your Notification Service (SNs). 
                 Message=json.dumps({"error": "Invalid Input", 'body': body}),    # Publish the error message in JSON format    
                Subject='Lambda Error')      # The subject of notification email  
            return {                      # Return a response to API Gateway that an event occurred and we failed validation 
              'statusCode': 400,           # HTTP status code for this request. Set it as bad (i.e., unsuccessful) if the input is invalid    
                'body': json.dumps('Invalid Input')   }    # Return a JSON response with an error message to API Gateway client      
        
        s3 = boto3.client(service='s3', region_name="us-west-2")  # Initialize S3 Client for interacting AWS services in 'US West (Oregon)' Region    
                                                                   # Replace with your actual bucket name and fileName from the event body   
        s3.upload_file(body['fileName'],'<Your Bucket Name>', parse.urlparse(event['headers']['host']).path + '/' + body['fileName'])  # Upload a specific S3 object with specified bucket name and file path  
                                                                                                                           
        sns.publish(    # Publishing the notification about successful upload of an item through Amazon Simple Notification Service (SNS)    
            TopicArn='<Your-SNs_TopicARN>',  # Replace with your actual ARN for Your SNS topic  
             Message=json.dumps({"success": "File Uploaded", 'body': body}),    # Publish the success message in JSON format    
            Subject='Lambda Success')      # The subject of notification email 
        return {                      # Return a response to API Gateway that an event occurred and we successfully uploaded file  
              'statusCode': 200,           # HTTP status code for this request. Set it as successful (i.e., success) if the operation is completed    
                'body': json.dumps('File Uploaded Successfully') }    # Return a JSON response with an message to API Gateway client      
                                                                  
    except Exception as e:             # Catch block for any exceptions that may occur during execution of try-block and publish error notification through SNS    
        sns.publish(                  # Publishing the notifications about failed operation via Amazon Simple Notification Service (SNS) 
            TopicArn='<Your_SNs_TopicARN>',   # Replace with your actual ARN for Your SNs topic   
             Message=json.dumps({"error": str(e), 'body': body}),     # Publish the error message in JSON format 
            Subject='Lambda Error')      # The subject of notification email      
        return {                      # Return a response to API Gateway that an event occurred and we failed due to exception   
              'statusCode': 500,           # HTTP status code for this request. Set it as internal server error (i.e., bad) if the operation is not completed    
                'body': json.dumps('Error Occurred') }   # Return a JSON response with an message to API Gateway client